/* 지식 평가 목록 조회 */
SELECT

  FROM  TB_DAM_KNO_IFM A
 WHERE  1=1

 ORDER  BY A.FRST_REGIST_PNTTM DESC
 LIMIT  #{recordCountPerPage} OFFSET #{firstIndex}

/* 지식 평가 상세 조회 */
SELECT

  FROM  TB_DAM_KNO_IFM A
 WHERE  A.KNWLDG_ID = #{knoId}

mapper.update:
/* 지식 평가 결과 수정 */
UPDATE  TB_DAM_KNO_IFM
   SET  KNWLDG_EVL      = #{knoAps}
      , EVL_DE          = #{appYmd}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  KNWLDG_ID = #{knoId}
